// src/pages/Dashboard.jsx
// Admin sees full overview: stats, member workload, overdue tasks
// Member sees their own task summary

import { useState, useEffect } from 'react';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();

  useEffect(() => {
    const fetchTasks = async () => {
      try {
        let allTasks = [];
        if (user?.role === 'admin') {
          const projectsRes = await API.get('/projects');
          const projects = projectsRes.data.projects;
          if (projects.length > 0) {
            const taskPromises = projects.map(p =>
              API.get(`/tasks?project=${p._id}`)
            );
            const taskResults = await Promise.all(taskPromises);
            allTasks = taskResults.flatMap(r => r.data.tasks);
          }
        } else {
          const res = await API.get('/tasks/my-tasks');
          allTasks = res.data.tasks;
        }
        setTasks(allTasks);
      } catch (err) {
        console.error('Failed to load tasks');
      } finally {
        setLoading(false);
      }
    };
    fetchTasks();
  }, [user]);

  // ── Stats calculations ──────────────────────────────────
  const total = tasks.length;
  const todo = tasks.filter(t => t.status === 'todo').length;
  const inProgress = tasks.filter(t => t.status === 'in-progress').length;
  const done = tasks.filter(t => t.status === 'done').length;
  const overdue = tasks.filter(t =>
    t.dueDate && new Date(t.dueDate) < new Date() && t.status !== 'done'
  ).length;
  const unassigned = tasks.filter(t => !t.assignedTo).length;

  // ── Admin stats (different labels) ─────────────────────
  const adminStats = [
    { label: 'Total Tasks', value: total, color: '#3b82f6', bg: '#eff6ff', icon: '📋' },
    { label: 'To Assign', value: unassigned, color: '#f59e0b', bg: '#fffbeb', icon: '📌' },
    { label: 'In Progress', value: inProgress, color: '#8b5cf6', bg: '#f5f3ff', icon: '⚙️' },
    { label: 'Completed', value: done, color: '#10b981', bg: '#ecfdf5', icon: '✅' },
    { label: 'Overdue', value: overdue, color: '#ef4444', bg: '#fef2f2', icon: '⚠️' },
  ];

  // ── Member stats ────────────────────────────────────────
  const memberStats = [
    { label: 'Total Tasks', value: total, color: '#3b82f6', bg: '#eff6ff', icon: '📋' },
    { label: 'To Do', value: todo, color: '#f59e0b', bg: '#fffbeb', icon: '📌' },
    { label: 'In Progress', value: inProgress, color: '#8b5cf6', bg: '#f5f3ff', icon: '⚙️' },
    { label: 'Done', value: done, color: '#10b981', bg: '#ecfdf5', icon: '✅' },
    { label: 'Overdue', value: overdue, color: '#ef4444', bg: '#fef2f2', icon: '⚠️' },
  ];

  const stats = user?.role === 'admin' ? adminStats : memberStats;

  // ── Member workload (admin only) ────────────────────────
  const memberMap = {};
  tasks.forEach(task => {
    if (task.assignedTo) {
      const name = task.assignedTo.name || 'Unknown';
      const id = task.assignedTo._id;
      if (!memberMap[id]) {
        memberMap[id] = { name, todo: 0, inProgress: 0, done: 0, total: 0 };
      }
      memberMap[id].total++;
      if (task.status === 'todo') memberMap[id].todo++;
      if (task.status === 'in-progress') memberMap[id].inProgress++;
      if (task.status === 'done') memberMap[id].done++;
    }
  });

  const overdueTasks = tasks.filter(t =>
    t.dueDate && new Date(t.dueDate) < new Date() && t.status !== 'done'
  );

  if (loading) {
    return (
      <div style={styles.loadingContainer}>
        <div style={styles.loadingText}>Loading dashboard...</div>
      </div>
    );
  }

  return (
    <div style={styles.container}>

      {/* ── Header ── */}
      <div style={styles.header}>
        <div>
          <h2 style={styles.title}>
            {user?.role === 'admin' ? '🛠️ Admin Dashboard' : '👋 My Dashboard'}
          </h2>
          <p style={styles.sub}>
            {user?.role === 'admin'
              ? `Full overview of all tasks across all projects`
              : `Welcome back, ${user?.name}! Here's your task summary`}
          </p>
        </div>
        <div style={{
          ...styles.roleBadge,
          background: user?.role === 'admin' ? '#dbeafe' : '#dcfce7',
          color: user?.role === 'admin' ? '#1d4ed8' : '#16a34a',
        }}>
          {user?.role === 'admin' ? '👑 Admin' : '👤 Member'}
        </div>
      </div>

      {/* ── Stats Cards ── */}
      <div style={styles.statsGrid}>
        {stats.map((stat) => (
          <div key={stat.label} style={{ ...styles.statCard, backgroundColor: stat.bg }}>
            <div style={styles.statIcon}>{stat.icon}</div>
            <div style={{ ...styles.statValue, color: stat.color }}>{stat.value}</div>
            <div style={styles.statLabel}>{stat.label}</div>
            {/* Progress bar */}
            <div style={styles.progressBg}>
              <div style={{
                ...styles.progressFill,
                width: total > 0 ? `${(stat.value / total) * 100}%` : '0%',
                backgroundColor: stat.color,
              }} />
            </div>
          </div>
        ))}
      </div>

      {/* ── Admin: Member Workload Table ── */}
      {user?.role === 'admin' && (
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>👥 Member Workload</h3>
          {Object.values(memberMap).length === 0 ? (
            <div style={styles.emptyBox}>
              <p>No tasks assigned to members yet.</p>
              <p style={{ fontSize: '13px', color: '#94a3b8' }}>
                Go to Projects → Tasks to assign tasks to members.
              </p>
            </div>
          ) : (
            <div style={styles.tableWrapper}>
              <table style={styles.table}>
                <thead>
                  <tr style={styles.tableHead}>
                    <th style={styles.th}>Member</th>
                    <th style={styles.th}>Total</th>
                    <th style={styles.th}>To Do</th>
                    <th style={styles.th}>In Progress</th>
                    <th style={styles.th}>Done</th>
                    <th style={styles.th}>Progress</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.values(memberMap).map((m) => (
                    <tr key={m.name} style={styles.tableRow}>
                      <td style={styles.td}>
                        <div style={styles.memberName}>
                          <div style={styles.avatar}>
                            {m.name.charAt(0).toUpperCase()}
                          </div>
                          {m.name}
                        </div>
                      </td>
                      <td style={{ ...styles.td, fontWeight: '600' }}>{m.total}</td>
                      <td style={{ ...styles.td, color: '#f59e0b' }}>{m.todo}</td>
                      <td style={{ ...styles.td, color: '#8b5cf6' }}>{m.inProgress}</td>
                      <td style={{ ...styles.td, color: '#10b981' }}>{m.done}</td>
                      <td style={styles.td}>
                        <div style={styles.progressBg}>
                          <div style={{
                            ...styles.progressFill,
                            width: `${m.total > 0 ? (m.done / m.total) * 100 : 0}%`,
                            backgroundColor: '#10b981',
                          }} />
                        </div>
                        <span style={{ fontSize: '11px', color: '#64748b' }}>
                          {m.total > 0 ? Math.round((m.done / m.total) * 100) : 0}% done
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {/* ── Overdue Tasks ── */}
      {overdueTasks.length > 0 && (
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>⚠️ Overdue Tasks</h3>
          <div style={styles.overdueList}>
            {overdueTasks.map(task => (
              <div key={task._id} style={styles.overdueCard}>
                <div style={styles.overdueLeft}>
                  <div style={styles.overdotRed} />
                  <div>
                    <div style={styles.overdueTitle}>{task.title}</div>
                    {task.assignedTo && (
                      <div style={styles.overdueAssignee}>
                        👤 {task.assignedTo.name}
                      </div>
                    )}
                  </div>
                </div>
                <div style={styles.overdueRight}>
                  <span style={styles.overdueDateBadge}>
                    📅 {new Date(task.dueDate).toLocaleDateString()}
                  </span>
                  <span style={styles.overdueDaysBadge}>
                    {Math.floor((new Date() - new Date(task.dueDate)) / 86400000)}d overdue
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── Recent Tasks ── */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>
          {user?.role === 'admin' ? '📋 All Recent Tasks' : '📋 My Recent Tasks'}
        </h3>

        {tasks.length === 0 ? (
          <div style={styles.emptyBox}>
            <p>
              {user?.role === 'admin'
                ? 'No tasks found. Create tasks in Projects!'
                : 'No tasks assigned to you yet.'}
            </p>
          </div>
        ) : (
          <div style={styles.taskList}>
            {tasks.slice(0, 8).map(task => (
              <div key={task._id} style={styles.taskRow}>
                <div style={styles.taskLeft}>
                  <div style={{
                    ...styles.statusDot,
                    background: task.status === 'done' ? '#10b981'
                      : task.status === 'in-progress' ? '#8b5cf6' : '#f59e0b',
                  }} />
                  <div>
                    <div style={styles.taskTitle}>{task.title}</div>
                    {task.project?.name && (
                      <div style={styles.taskProject}>📁 {task.project.name}</div>
                    )}
                  </div>
                </div>
                <div style={styles.taskRight}>
                  {task.assignedTo && (
                    <span style={styles.assigneeBadge}>
                      👤 {task.assignedTo.name}
                    </span>
                  )}
                  <span style={{
                    ...styles.statusBadge,
                    background: task.status === 'done' ? '#dcfce7'
                      : task.status === 'in-progress' ? '#ede9fe' : '#fef3c7',
                    color: task.status === 'done' ? '#16a34a'
                      : task.status === 'in-progress' ? '#7c3aed' : '#b45309',
                  }}>
                    {task.status === 'in-progress' ? 'In Progress'
                      : task.status === 'done' ? 'Done' : 'To Do'}
                  </span>
                  <span style={{
                    ...styles.priorityDot,
                    background: task.priority === 'high' ? '#ef4444'
                      : task.priority === 'medium' ? '#f59e0b' : '#10b981',
                  }} title={`${task.priority} priority`} />
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

    </div>
  );
};

const styles = {
  container: { maxWidth: '960px', margin: '0 auto', paddingBottom: '40px' },
